import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  FEDEX_ADMIN = 'FEDEX_ADMIN',
  DCA_MANAGER = 'DCA_MANAGER'
}

export enum AgencyStatus {
  ACTIVE = 'Active',
  PROBATION = 'Probation',
  SUSPENDED = 'Suspended',
  ONBOARDING = 'Onboarding'
}

export interface Agency {
  id: string;
  name: string;
  region: string;
  status: AgencyStatus;
  complianceScore: number;
  recoveryRate: number;
  activeCases: number;
  contactEmail: string;
  lastAuditDate: string;
}

export interface DebtBatch {
  id: string;
  batchName: string;
  totalAmount: number;
  currency: string;
  assignedAgencyId: string | null;
  status: 'Unassigned' | 'Assigned' | 'Closed';
  createdDate: string;
  riskLevel: 'Low' | 'Medium' | 'High';
}

export interface PerformanceMetric {
  month: string;
  recoveryAmount: number;
  targetAmount: number;
}

import { GoogleGenAI } from "@google/genai";
import { Agency } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeAgencyRisk = async (agency: Agency): Promise<string> => {
  try {
    const prompt = `
      You are a senior risk compliance officer at FedEx. 
      Analyze the following Debt Collection Agency (DCA) for potential risks based on their data.

      Agency Name: ${agency.name}
      Status: ${agency.status}
      Compliance Score: ${agency.complianceScore}/100
      Recovery Rate: ${agency.recoveryRate}%
      Active Cases: ${agency.activeCases}
      Last Audit: ${agency.lastAuditDate}

      Provide a concise, professional executive summary (max 100 words). 
      Highlight if they should be retained, put on probation, or audited. 
      Focus on financial risk and brand reputation.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Unable to generate analysis at this time.";
  } catch (error) {
    console.error("Gemini analysis failed", error);
    return "AI Analysis unavailable due to system error.";
  }
};

export const generateBatchStrategy = async (batchDetails: string): Promise<string> => {
  try {
    const prompt = `
      You are a debt recovery strategist. 
      Suggest a placement strategy for this debt batch: "${batchDetails}".
      Recommend the type of agency (e.g., litigation specialized, early-stage soft collection, international) suitable for this batch.
      Keep it brief and professional.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "No strategy generated.";
  } catch (error) {
    console.error("Gemini strategy failed", error);
    return "AI Strategy unavailable.";
  }
}

