import React, { useState } from 'react';
import { DebtBatch } from '../types';
import { Briefcase, ArrowRight, CheckCircle2, Bot, AlertCircle } from 'lucide-react';
import { generateBatchStrategy } from '../services/geminiService';

const mockBatches: DebtBatch[] = [
  { id: 'B-1029', batchName: 'Q3 Consumer Tech Write-offs', totalAmount: 1250000, currency: 'USD', assignedAgencyId: null, status: 'Unassigned', createdDate: '2024-02-10', riskLevel: 'Medium' },
  { id: 'B-1030', batchName: 'Logistics Small Biz Defaults', totalAmount: 450000, currency: 'USD', assignedAgencyId: null, status: 'Unassigned', createdDate: '2024-02-12', riskLevel: 'High' },
  { id: 'B-1031', batchName: 'Enterprise Late Fees - EU', totalAmount: 890000, currency: 'EUR', assignedAgencyId: '2', status: 'Assigned', createdDate: '2024-01-20', riskLevel: 'Low' },
];

export const DebtAssignment: React.FC = () => {
  const [selectedBatch, setSelectedBatch] = useState<DebtBatch | null>(null);
  const [aiSuggestion, setAiSuggestion] = useState<string>('');
  const [loadingSuggestion, setLoadingSuggestion] = useState(false);

  const handleSelectBatch = async (batch: DebtBatch) => {
    setSelectedBatch(batch);
    if (batch.status === 'Unassigned') {
        setLoadingSuggestion(true);
        setAiSuggestion('');
        const suggestion = await generateBatchStrategy(`Batch: ${batch.batchName}, Amount: ${batch.totalAmount} ${batch.currency}, Risk: ${batch.riskLevel}`);
        setAiSuggestion(suggestion);
        setLoadingSuggestion(false);
    }
  };

  return (
    <div className="p-8 h-full flex flex-col">
       <div className="mb-6">
          <h1 className="text-2xl font-bold text-gray-900">Debt Pool Assignment</h1>
          <p className="text-gray-500 text-sm mt-1">Allocate debt portfolios to approved agencies based on performance capacity.</p>
      </div>

      <div className="grid grid-cols-12 gap-6 h-full">

        {/* Batch List */}
        <div className="col-span-8 bg-white rounded-lg border border-gray-200 shadow-sm flex flex-col overflow-hidden">
            <div className="p-4 border-b border-gray-200 bg-gray-50 font-semibold text-gray-700 flex justify-between items-center">
                <span>Available Batches</span>
                <span className="text-xs font-normal text-gray-500 bg-white border border-gray-200 px-2 py-1 rounded">Sorted by: Created Date</span>
            </div>
            <div className="overflow-y-auto flex-1 p-2">
                {mockBatches.map(batch => (
                    <div 
                        key={batch.id} 
                        onClick={() => handleSelectBatch(batch)}
                        className={`p-4 mb-2 rounded border cursor-pointer transition-all ${selectedBatch?.id === batch.id ? 'border-[#4D148C] bg-purple-50 ring-1 ring-[#4D148C]' : 'border-gray-200 hover:border-gray-300 bg-white'}`}
                    >
                        <div className="flex justify-between items-center mb-2">
                            <h3 className="font-semibold text-gray-900">{batch.batchName}</h3>
                            <span className={`px-2 py-1 text-xs rounded-full ${batch.status === 'Assigned' ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-700'}`}>
                                {batch.status}
                            </span>
                        </div>
                        <div className="flex justify-between text-sm text-gray-600">
                             <span>ID: {batch.id}</span>
                             <span className="font-medium text-gray-900">{batch.currency} {batch.totalAmount.toLocaleString()}</span>
                        </div>
                         <div className="flex items-center mt-3 text-xs space-x-3">
                             <span className={`px-2 py-0.5 rounded border ${batch.riskLevel === 'High' ? 'bg-red-50 border-red-100 text-red-700' : 'bg-blue-50 border-blue-100 text-blue-700'}`}>
                                 Risk: {batch.riskLevel}
                             </span>
                             <span className="text-gray-400">Created: {batch.createdDate}</span>
                         </div>
                    </div>
                ))}
            </div>
        </div>

        {/* Assignment Panel */}
        <div className="col-span-4 bg-white rounded-lg border border-gray-200 shadow-sm flex flex-col">
            <div className="p-4 border-b border-gray-200 bg-[#4D148C] text-white rounded-t-lg">
                <h2 className="font-semibold">Assignment Console</h2>
            </div>

            <div className="p-6 flex-1 flex flex-col">
                {selectedBatch ? (
                    <>
                        <div className="mb-6">
                            <span className="text-xs uppercase text-gray-500 font-bold tracking-wider">Selected Batch</span>
                            <h3 className="text-xl font-bold text-gray-900 mt-1">{selectedBatch.batchName}</h3>
                            <p className="text-2xl font-light text-[#4D148C] mt-2">
                                {selectedBatch.currency} {selectedBatch.totalAmount.toLocaleString()}
                            </p>
                        </div>

                        {selectedBatch.status === 'Unassigned' ? (
                            <div className="space-y-6 flex-1">

                                {/* AI Strategy Box */}
                                <div className="bg-indigo-50 border border-indigo-100 rounded-lg p-4">
                                    <div className="flex items-center mb-2 text-indigo-800">
                                        <Bot size={18} className="mr-2" />
                                        <span className="text-sm font-bold">AI Placement Strategy</span>
                                    </div>
                                    {loadingSuggestion ? (
                                        <div className="space-y-2 animate-pulse">
                                            <div className="h-2 bg-indigo-200 rounded w-3/4"></div>
                                            <div className="h-2 bg-indigo-200 rounded w-1/2"></div>
                                        </div>
                                    ) : (
                                        <p className="text-sm text-indigo-900 italic">
                                            "{aiSuggestion}"
                                        </p>
                                    )}
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-2">Assign to Agency</label>
                                    <select className="w-full border-gray-300 rounded-md shadow-sm focus:border-[#4D148C] focus:ring focus:ring-[#4D148C] focus:ring-opacity-50 h-10 border px-3">
                                        <option value="">Select an Agency...</option>
                                        <option value="1">Global Recovery Partners (Rec: 98%)</option>
                                        <option value="2">Apex Debt Solutions (Rec: 85%)</option>
                                        <option value="5">FedEx Internal Ops (Rec: 100%)</option>
                                    </select>
                                    <p className="text-xs text-gray-500 mt-1">Only active and compliant agencies are listed.</p>
                                </div>

                                <div className="mt-auto">
                                    <button className="w-full bg-[#FF6600] hover:bg-[#e55b00] text-white font-medium py-2 px-4 rounded shadow-sm flex justify-center items-center">
                                        Confirm Assignment <ArrowRight size={16} className="ml-2" />
                                    </button>
                                </div>
                            </div>
                        ) : (
                             <div className="flex flex-col items-center justify-center h-full text-center p-6 text-gray-500 bg-gray-50 rounded border border-dashed border-gray-300">
                                <CheckCircle2 size={48} className="text-green-500 mb-4" />
                                <h3 className="text-lg font-medium text-gray-900">Already Assigned</h3>
                                <p className="text-sm mt-2">This batch was assigned to Agency ID: {selectedBatch.assignedAgencyId} on Jan 20, 2024.</p>
                            </div>
                        )}
                    </>
                ) : (
                    <div className="flex flex-col items-center justify-center h-full text-center p-6 text-gray-400">
                        <Briefcase size={48} className="mb-4 opacity-50" />
                        <p>Select a debt batch from the list to view details and assign.</p>
                    </div>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

