      case 'agencies':
        return userRole === UserRole.FEDEX_ADMIN ? <AgencyList /> : <div className="p-8 text-gray-500">Access Restricted</div>;
      case 'debt-pool':
        return userRole === UserRole.FEDEX_ADMIN ? <DebtAssignment /> : <div className="p-8 text-gray-500">Access Restricted</div>;
      case 'compliance':
        return <div className="p-8 flex items-center justify-center h-full text-gray-400">Compliance Module Coming Soon</div>;
      default:
        return <div className="p-8 flex items-center justify-center h-full text-gray-400">Module Under Construction</div>;
    }
  };

  return (
    <Layout 
        currentView={currentView} 
        setCurrentView={setCurrentView} 
        role={userRole}
        setRole={setUserRole}
    >
      {renderContent()}
    </Layout>
  );
}

